import{c as a,Q as o,j as r,m as t}from"./chunks/framework.Bj0Eefkv.js";const u=JSON.parse('{"title":"Padrão de Portas e Configuração de Firewall","description":"","frontmatter":{},"headers":[],"relativePath":"infraestrutura/portas-e-firewall.md","filePath":"infraestrutura/portas-e-firewall.md","lastUpdated":1784161795000}'),s={name:"infraestrutura/portas-e-firewall.md"};function i(n,e,d,c,p,l){return o(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="padrao-de-portas-e-configuracao-de-firewall" tabindex="-1">Padrão de Portas e Configuração de Firewall <a class="header-anchor" href="#padrao-de-portas-e-configuracao-de-firewall" aria-label="Permalink to &quot;Padrão de Portas e Configuração de Firewall&quot;">​</a></h1><blockquote><p>⚠️ <strong>Atenção — Segurança crítica</strong> Portas abertas desnecessariamente na internet são vetores reais de invasão, ransomware e vazamento de dados. Toda porta listada neste documento deve ser acessível <strong>apenas na rede interna ou via VPN</strong>. Nunca exponha portas de aplicação, banco de dados ou serviços internos diretamente para a internet.</p></blockquote><hr><h2 id="por-que-isso-e-importante" tabindex="-1">Por que isso é importante <a class="header-anchor" href="#por-que-isso-e-importante" aria-label="Permalink to &quot;Por que isso é importante&quot;">​</a></h2><h3 id="o-que-acontece-quando-portas-internas-ficam-expostas" tabindex="-1">O que acontece quando portas internas ficam expostas <a class="header-anchor" href="#o-que-acontece-quando-portas-internas-ficam-expostas" aria-label="Permalink to &quot;O que acontece quando portas internas ficam expostas&quot;">​</a></h3><p>Quando serviços internos são acessíveis diretamente pela internet, eles se tornam alvos de ataques automatizados que operam 24 horas por dia, 7 dias por semana. O processo começa com varreduras de portas — ferramentas que percorrem faixas de endereços IP em busca de serviços conhecidos. Uma vez identificado um serviço exposto, ferramentas especializadas tentam explorar vulnerabilidades conhecidas naquele serviço, testar credenciais padrão ou forçar autenticação por dicionário.</p><p>O risco não é teórico. Sistemas ERP e de hotelaria são alvos especialmente atrativos porque:</p><ul><li><strong>Concentram dados financeiros sensíveis</strong> — transações de cartão (mesmo que tokenizadas), histórico de pagamentos, contas a receber e a pagar</li><li><strong>Armazenam dados pessoais de hóspedes</strong> — CPF, passaporte, endereço, dados de contato, preferências — informações com alto valor no mercado de dados roubados</li><li><strong>Têm acesso direto ao PDV e ao TEF</strong> — um atacante com acesso ao servidor de contas pode interceptar ou manipular transações em andamento</li><li><strong>Operam em ambientes onde a TI é enxuta</strong> — hotéis e restaurantes frequentemente não têm equipe de segurança dedicada, o que torna a superfície de ataque maior</li></ul><h3 id="vetores-de-ataque-comuns-em-ambientes-erp-expostos" tabindex="-1">Vetores de ataque comuns em ambientes ERP expostos <a class="header-anchor" href="#vetores-de-ataque-comuns-em-ambientes-erp-expostos" aria-label="Permalink to &quot;Vetores de ataque comuns em ambientes ERP expostos&quot;">​</a></h3><p><strong>Exploração de banco de dados exposto:</strong> bancos como PostgreSQL, quando acessíveis na internet sem autenticação forte ou restrição de IP, são varridos por scanners automatizados em questão de horas após a exposição. A partir de um banco comprometido, o atacante obtém acesso a toda a base de dados do cliente — incluindo senhas, configurações e dados transacionais.</p><p><strong>Ataque a serviços de sincronização e back office:</strong> portas de sincronização entre filiais ou entre servidor e PDV raramente têm autenticação robusta — são projetadas para operar em rede confiável. Expostas na internet, tornam-se pontos de entrada sem resistência significativa.</p><p><strong>Ransomware via acesso a servidor de aplicação:</strong> após obter acesso ao servidor, atacantes instalam ransomware que criptografa o banco de dados e os arquivos do sistema, tornando o ambiente completamente inoperante. No setor de hotelaria, isso significa incapacidade de fazer check-in, processar pagamentos ou acessar reservas — pressão enorme para pagamento de resgate.</p><p><strong>Movimentação lateral:</strong> uma porta exposta raramente é o destino final do atacante. É a porta de entrada para movimentação lateral na rede interna, comprometendo outros sistemas, servidores de backup e credenciais de administrador.</p><h3 id="rede-interna-vpn-e-exposicao-publica-—-a-distincao-que-importa" tabindex="-1">Rede interna, VPN e exposição pública — a distinção que importa <a class="header-anchor" href="#rede-interna-vpn-e-exposicao-publica-—-a-distincao-que-importa" aria-label="Permalink to &quot;Rede interna, VPN e exposição pública — a distinção que importa&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Contexto</th><th>O que significa</th><th>Nível de risco</th></tr></thead><tbody><tr><td>Rede interna (LAN)</td><td>Tráfego restrito ao ambiente físico ou VLAN do cliente</td><td>Baixo — contanto que a rede interna seja segmentada</td></tr><tr><td>VPN autenticada</td><td>Túnel criptografado com autenticação de usuário/dispositivo</td><td>Aceitável — para acesso remoto legítimo</td></tr><tr><td>Internet pública</td><td>Qualquer endereço IP do mundo pode tentar conexão</td><td>Inaceitável para serviços internos</td></tr></tbody></table><blockquote><p>ℹ️ A Desbravador fornece o software — a segurança da infraestrutura de rede é responsabilidade do cliente (LICENCIADO) e da equipe de TI responsável pela implantação.</p></blockquote><hr><h2 id="principios-de-firewall-para-ambientes-desbravador" tabindex="-1">Princípios de firewall para ambientes Desbravador <a class="header-anchor" href="#principios-de-firewall-para-ambientes-desbravador" aria-label="Permalink to &quot;Princípios de firewall para ambientes Desbravador&quot;">​</a></h2><p>A configuração correta do firewall é a primeira e mais importante linha de defesa. Os princípios a seguir não são opcionais — são requisitos mínimos para operação segura.</p><p><strong>Princípio do menor privilégio:</strong> abra apenas as portas estritamente necessárias para o funcionamento do sistema. Cada porta aberta é uma superfície de ataque potencial. Se não há necessidade operacional documentada, a porta deve estar fechada.</p><p><strong>Serviços internos ficam na rede interna:</strong> qualquer porta da faixa 17000–17999 e 18500–18999 que opere no contexto &quot;Local&quot; deve ser acessível apenas dentro da rede do cliente. Nunca deve haver uma regra de firewall permitindo acesso externo a esses serviços.</p><p><strong>Banco de dados: acesso exclusivo pelo servidor de aplicação:</strong> o PostgreSQL (porta 5432) jamais deve ter uma regra de firewall que permita conexão de fora do servidor de aplicação. A regra correta é: somente o IP do servidor de aplicação pode conectar na porta 5432, e apenas na rede interna.</p><p><strong>Acesso externo legítimo via VPN obrigatoriamente:</strong> qualquer necessidade de acesso remoto — manutenção, suporte técnico, acesso de gestores externos — deve ser feita via VPN com autenticação forte. MFA (autenticação de múltiplos fatores) é fortemente recomendado.</p><p><strong>Monitoramento de tentativas de acesso não autorizado:</strong> o firewall deve registrar tentativas de conexão em portas não autorizadas. Picos de tentativas de varredura são sinal precoce de reconhecimento de alvo — permitem ação preventiva antes de uma exploração efetiva.</p><p><strong>Revisão periódica das regras:</strong> regras de firewall acumulam exceções ao longo do tempo. Cada nova regra adicionada deve ter justificativa documentada, responsável e prazo de revisão. Regras sem uso devem ser removidas.</p><hr><h2 id="urls-obrigatorias-—-liberacao-em-proxy-e-firewall-de-saida" tabindex="-1">URLs obrigatórias — liberação em proxy e firewall de saída <a class="header-anchor" href="#urls-obrigatorias-—-liberacao-em-proxy-e-firewall-de-saida" aria-label="Permalink to &quot;URLs obrigatórias — liberação em proxy e firewall de saída&quot;">​</a></h2><p>O endereço abaixo deve estar <strong>permitido (bypass)</strong> em todos os proxies, filtros de conteúdo e firewalls de saída do cliente. O bloqueio desta URL impede o funcionamento de serviços essenciais do sistema Desbravador.</p><table tabindex="0"><thead><tr><th>URL</th><th>Protocolo</th><th>Porta</th><th>Finalidade</th></tr></thead><tbody><tr><td><code>https://servicos.desbravador.com.br/</code></td><td>HTTPS</td><td>443</td><td>Serviços online do sistema Desbravador</td></tr></tbody></table><blockquote><p>⚠️ <strong>Atenção — Liberação obrigatória</strong> Firewalls, proxies corporativos e soluções de filtragem de conteúdo (ex.: Fortinet, Sophos, pfSense com filtro de URL, Squid) podem bloquear este endereço por padrão. Verificar e adicionar a exceção antes da implantação. A ausência da liberação pode causar falhas silenciosas em funcionalidades do sistema que dependem de comunicação com os servidores da Desbravador.</p></blockquote><hr><h2 id="faixas-de-portas-por-sistema" tabindex="-1">Faixas de portas por sistema <a class="header-anchor" href="#faixas-de-portas-por-sistema" aria-label="Permalink to &quot;Faixas de portas por sistema&quot;">​</a></h2><p>Entrar em contato com o suporte da Desbravador e verificar quais são as portas recomendadas.</p><p><a href="https://desbravador.movidesk.com/kb/pt-br/article/270137/orientacoes-de-padrao-de-portas-dos-aplicativos-dsl" target="_blank" rel="noreferrer">https://desbravador.movidesk.com/kb/pt-br/article/270137/orientacoes-de-padrao-de-portas-dos-aplicativos-dsl</a></p><blockquote><p>🔴 <strong>Nunca abra o PostgreSQL (porta 5432) para a internet.</strong> Existem scanners automáticos que varrem a internet 24 horas por dia em busca de bancos de dados expostos. Um servidor PostgreSQL acessível publicamente sem VPN é detectado em minutos. A partir daí, tentativas de autenticação por força bruta, exploração de vulnerabilidades conhecidas e, em casos de configuração fraca, acesso direto sem senha são consequências praticamente certas. Um banco comprometido significa perda total de confidencialidade de todos os dados do cliente.</p></blockquote><hr><h2 id="contato-e-suporte" tabindex="-1">Contato e Suporte <a class="header-anchor" href="#contato-e-suporte" aria-label="Permalink to &quot;Contato e Suporte&quot;">​</a></h2><p>Dúvidas sobre a configuração de portas, integração de firewall ou arquitetura de rede para ambientes Desbravador devem ser encaminhadas ao suporte técnico:</p><ul><li><strong>Portal de suporte:</strong> <a href="https://suporte.desbravador.com.br" target="_blank" rel="noreferrer">suporte.desbravador.com.br</a></li><li><strong>Base de conhecimento:</strong> Artigo de referência original — <em>&quot;Orientações de padrão de portas dos aplicativos DSL&quot;</em> (Eduardo Henrique Kawaguchi, atualizado em 31/05/2026)</li></ul><blockquote><p>ℹ️ Este documento é uma referência técnica para a equipe de TI do cliente. A Desbravador não realiza configuração de firewall ou infraestrutura de rede — essa responsabilidade é do cliente ou do fornecedor de infraestrutura contratado. Em caso de dúvida sobre a configuração correta, consulte o suporte antes de abrir regras de firewall.</p></blockquote><hr><p><em>Documento gerado em 31/05/2026 — baseado na versão v.40 das orientações de portas DSL.</em></p>',42)])])}const b=a(s,[["render",i]]);export{u as __pageData,b as default};
